"use client";

import {
  memo,
  useState,
  useCallback,
  type ReactNode,
} from "react";
import type { ContentPart, ToolCallEvent } from "@polpo-ai/sdk";
import { Copy, Check, FileCode } from "lucide-react";
import { Streamdown } from "streamdown";
import { getTextContent } from "../lib/get-text-content";
import { relativeTime } from "../lib/relative-time";
import { ToolCallChip } from "../tools";
import { ChatTyping } from "./chat-typing";

/** Components override accepted by Streamdown — use Record for flexibility. */
type StreamdownComponentsProp = Record<string, unknown>;

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface ChatMessageItemData {
  id?: string;
  role: "user" | "assistant";
  content: string | ContentPart[];
  ts?: string;
  toolCalls?: ToolCallEvent[];
}

export interface ChatMessageProps {
  msg: ChatMessageItemData;
  isLast?: boolean;
  isStreaming?: boolean;
  avatar?: ReactNode;
  agentName?: string;
  streamdownComponents?: StreamdownComponentsProp;
  /** Resolve a file_id to a URL for file attachment links. Defaults to `/api/v1/files/read?path=<file_id>`. */
  resolveFileUrl?: (fileId: string) => string;
  className?: string;
}

/* ------------------------------------------------------------------ */
/*  CopyButton                                                         */
/* ------------------------------------------------------------------ */

function CopyButton({ text }: { text: string }) {
  const [copied, setCopied] = useState(false);

  const handleCopy = useCallback(() => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 1500);
  }, [text]);

  return (
    <button
      type="button"
      onClick={handleCopy}
      aria-label="Copy message"
      className="inline-flex items-center justify-center rounded-md p-1 text-gray-400 hover:text-gray-900 hover:bg-gray-100 transition-colors"
    >
      {copied ? <Check className="size-3.5" /> : <Copy className="size-3.5" />}
    </button>
  );
}

/* ------------------------------------------------------------------ */
/*  File / image content parts                                         */
/* ------------------------------------------------------------------ */

const defaultResolveFileUrl = (fileId: string) =>
  `/api/v1/files/read?path=${encodeURIComponent(fileId)}`;

function ContentParts({
  parts,
  align,
  resolveFileUrl = defaultResolveFileUrl,
}: {
  parts: ContentPart[];
  align: "start" | "end";
  resolveFileUrl?: (fileId: string) => string;
}) {
  const nonText = parts.filter((p) => p.type !== "text");
  if (nonText.length === 0) return null;

  return (
    <div
      className={`flex flex-wrap gap-1.5 mb-1 ${align === "end" ? "justify-end" : ""}`}
    >
      {nonText.map((part, i) => {
        if (part.type === "image_url") {
          return (
            <a
              key={i}
              href={(part as { type: "image_url"; image_url: { url: string } }).image_url.url}
              target="_blank"
              rel="noopener noreferrer"
              className="rounded-lg overflow-hidden max-w-[200px]"
            >
              <img
                src={(part as { type: "image_url"; image_url: { url: string } }).image_url.url}
                alt=""
                className="w-full h-auto block"
              />
            </a>
          );
        }
        if (part.type === "file") {
          const fileId = (part as { type: "file"; file_id: string }).file_id;
          const fn = fileId.split("/").pop() || fileId;
          return (
            <a
              key={i}
              href={resolveFileUrl(fileId)}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-1.5 bg-gray-100 border border-gray-200 rounded-lg px-2.5 py-1.5 text-xs text-gray-900 hover:border-gray-400 transition-colors"
            >
              <FileCode size={13} />
              <span className="truncate max-w-[120px]">{fn}</span>
            </a>
          );
        }
        return null;
      })}
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  ChatUserMessage                                                    */
/* ------------------------------------------------------------------ */

export const ChatUserMessage = memo(
  function ChatUserMessage({
    msg,
    isLast,
    isStreaming,
    resolveFileUrl,
    className,
  }: {
    msg: ChatMessageItemData;
    isLast?: boolean;
    isStreaming?: boolean;
    resolveFileUrl?: (fileId: string) => string;
    className?: string;
  }) {
    const text = getTextContent(msg.content);

    return (
      <div className={`w-full px-6 py-3 ${className ?? ""}`}>
        <div className="max-w-3xl mx-auto">
          <div className="group flex w-full flex-col gap-2 ml-auto justify-end">
            {/* File/image parts */}
            {Array.isArray(msg.content) && (
              <ContentParts parts={msg.content} align="end" resolveFileUrl={resolveFileUrl} />
            )}

            {/* Message bubble */}
            <div className="w-fit max-w-[80%] ml-auto rounded-[18px_18px_4px_18px] bg-gray-100 px-4 py-3">
              {text ? (
                <p className="whitespace-pre-wrap break-words text-gray-900">
                  {text}
                </p>
              ) : null}
            </div>

            {/* Hover actions: timestamp + copy */}
            {text && (!isLast || !isStreaming) && (
              <div className="flex items-center justify-end gap-1.5 h-6">
                <span className="text-[11px] text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity">
                  {msg.ts ? relativeTime(msg.ts) : ""}
                </span>
                <div className="opacity-0 group-hover:opacity-100 transition-opacity">
                  <CopyButton text={text} />
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  },
  (prev, next) =>
    prev.isLast === next.isLast &&
    prev.isStreaming === next.isStreaming &&
    prev.msg.id === next.msg.id &&
    prev.msg.content === next.msg.content,
);

/* ------------------------------------------------------------------ */
/*  ChatAssistantMessage                                               */
/* ------------------------------------------------------------------ */

export const ChatAssistantMessage = memo(
  function ChatAssistantMessage({
    msg,
    isLast,
    isStreaming,
    avatar,
    agentName,
    streamdownComponents: components,
    resolveFileUrl,
    className,
  }: {
    msg: ChatMessageItemData;
    isLast?: boolean;
    isStreaming?: boolean;
    avatar?: ReactNode;
    agentName?: string;
    streamdownComponents?: StreamdownComponentsProp;
    resolveFileUrl?: (fileId: string) => string;
    className?: string;
  }) {
    const text = getTextContent(msg.content);
    const filteredToolCalls = msg.toolCalls?.filter(
      (tc) => tc.name !== "ask_user_question",
    );

    return (
      <div className={`w-full px-6 pt-4 pb-6 ${className ?? ""}`}>
        <div className="max-w-3xl mx-auto">
          <div className="group flex w-full flex-col gap-2">
            {/* Avatar + name header */}
            {(avatar || agentName) && (
              <div className="flex items-center gap-2 mb-1">
                {avatar}
                {agentName && (
                  <span className="text-[13px] font-semibold text-gray-900">
                    {agentName}
                  </span>
                )}
              </div>
            )}

            {/* Tool calls */}
            {filteredToolCalls && filteredToolCalls.length > 0 && (
              <div className="flex flex-col gap-1 mb-1">
                {filteredToolCalls.map((tc) => (
                  <ToolCallChip key={tc.id} tool={tc} />
                ))}
              </div>
            )}

            {/* File/image parts */}
            {Array.isArray(msg.content) && (
              <ContentParts parts={msg.content} align="start" resolveFileUrl={resolveFileUrl} />
            )}

            {/* Text content or typing dots */}
            <div className="w-full text-gray-900">
              {text ? (
                components ? (
                  <Streamdown
                    className="size-full [&>*:first-child]:mt-0 [&>*:last-child]:mb-0"
                    components={components as any}
                  >
                    {text}
                  </Streamdown>
                ) : (
                  <p className="whitespace-pre-wrap break-words">{text}</p>
                )
              ) : (
                !filteredToolCalls?.length && <ChatTyping className="pt-1" />
              )}
            </div>

            {/* Hover action: copy */}
            {text && (!isLast || !isStreaming) && (
              <div className="h-6 flex items-center opacity-0 group-hover:opacity-100 transition-opacity">
                <CopyButton text={text} />
              </div>
            )}
          </div>
        </div>
      </div>
    );
  },
  (prev, next) =>
    prev.avatar === next.avatar &&
    prev.agentName === next.agentName &&
    prev.isLast === next.isLast &&
    prev.isStreaming === next.isStreaming &&
    prev.streamdownComponents === next.streamdownComponents &&
    prev.msg.id === next.msg.id &&
    prev.msg.content === next.msg.content &&
    prev.msg.toolCalls?.length === next.msg.toolCalls?.length &&
    JSON.stringify(prev.msg.toolCalls?.map((t) => t.state)) ===
      JSON.stringify(next.msg.toolCalls?.map((t) => t.state)),
);

/* ------------------------------------------------------------------ */
/*  ChatMessage — dispatcher                                           */
/* ------------------------------------------------------------------ */

export const ChatMessage = memo(
  function ChatMessage({
    msg,
    isLast,
    isStreaming,
    avatar,
    agentName,
    streamdownComponents,
    resolveFileUrl,
    className,
  }: ChatMessageProps) {
    if (msg.role === "user") {
      return (
        <ChatUserMessage msg={msg} isLast={isLast} isStreaming={isStreaming} resolveFileUrl={resolveFileUrl} className={className} />
      );
    }

    return (
      <ChatAssistantMessage
        msg={msg}
        isLast={isLast}
        isStreaming={isStreaming}
        avatar={avatar}
        agentName={agentName}
        streamdownComponents={streamdownComponents}
        resolveFileUrl={resolveFileUrl}
        className={className}
      />
    );
  },
  (prev, next) =>
    prev.avatar === next.avatar &&
    prev.agentName === next.agentName &&
    prev.isLast === next.isLast &&
    prev.isStreaming === next.isStreaming &&
    prev.streamdownComponents === next.streamdownComponents &&
    prev.resolveFileUrl === next.resolveFileUrl &&
    prev.className === next.className &&
    prev.msg.id === next.msg.id &&
    prev.msg.content === next.msg.content &&
    prev.msg.role === next.msg.role &&
    prev.msg.toolCalls?.length === next.msg.toolCalls?.length &&
    JSON.stringify(prev.msg.toolCalls?.map((t) => t.state)) ===
      JSON.stringify(next.msg.toolCalls?.map((t) => t.state)),
);

"use client";

import {
  useCallback,
  useEffect,
  useImperativeHandle,
  useRef,
  useState,
  type ReactNode,
} from "react";
import { Virtuoso, type VirtuosoHandle } from "react-virtuoso";
import type { ChatMessage } from "@polpo-ai/sdk";
import { useChatContext } from "./chat-provider";
import { ChatSkeleton } from "./chat-skeleton";
import { ChatScrollButton } from "./chat-scroll-button";
import { getTextContent } from "../lib/get-text-content";

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface ChatMessagesHandle {
  /** Scroll the list to the bottom. */
  scrollToBottom: (behavior?: "smooth" | "auto") => void;
}

export interface ChatMessagesProps {
  /**
   * Custom renderer for each message.
   * Receives the message, its index, whether it is the last item, and
   * whether the assistant is currently streaming.
   */
  renderItem?: (
    msg: ChatMessage,
    index: number,
    isLast: boolean,
    isStreaming: boolean,
  ) => ReactNode;
  /** Extra classes applied to the Virtuoso container. */
  className?: string;
  /** Number of skeleton pairs to show during the initial load. */
  skeletonCount?: number;
}

/* ------------------------------------------------------------------ */
/*  Default renderer (plain text fallback)                             */
/* ------------------------------------------------------------------ */

function DefaultMessageItem({ msg }: { msg: ChatMessage }) {
  const text = getTextContent(msg.content);
  return (
    <div className="w-full px-6 py-3">
      <div className="max-w-3xl mx-auto">
        <p className="text-xs font-medium opacity-50 mb-1">
          {msg.role === "user" ? "You" : "Assistant"}
        </p>
        <p className="whitespace-pre-wrap">{text}</p>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Footer (keeps Virtuoso happy for follow-output)                    */
/* ------------------------------------------------------------------ */

function VirtuosoFooter() {
  return <div className="h-px" aria-hidden="true" />;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export function ChatMessages({
  renderItem,
  className,
  skeletonCount = 3,
  ref,
}: ChatMessagesProps & { ref?: React.Ref<ChatMessagesHandle> }) {
    const { messages, isStreaming, status } = useChatContext();

    /* ── Virtuoso ref & scroll state ────────────────────────────── */
    const virtuosoRef = useRef<VirtuosoHandle>(null);
    const [isAtBottom, setIsAtBottom] = useState(true);
    const [showNewMessage, setShowNewMessage] = useState(false);
    const prevMessageCountRef = useRef(0);
    const hasInitialScrollRef = useRef(false);

    /* ── Scroll helpers ─────────────────────────────────────────── */
    const scrollToBottom = useCallback(
      (behavior: "smooth" | "auto" = "smooth") => {
        virtuosoRef.current?.scrollToIndex({
          index: "LAST",
          align: "end",
          behavior,
        });
        setShowNewMessage(false);
      },
      [],
    );

    useImperativeHandle(ref, () => ({ scrollToBottom }), [scrollToBottom]);

    /* ── Bottom-state change handler ────────────────────────────── */
    const handleAtBottomStateChange = useCallback((atBottom: boolean) => {
      setIsAtBottom(atBottom);
      if (atBottom) setShowNewMessage(false);
    }, []);

    /* ── Initial scroll to bottom once messages load ────────────── */
    useEffect(() => {
      if (messages.length > 0 && !hasInitialScrollRef.current) {
        hasInitialScrollRef.current = true;
        requestAnimationFrame(() =>
          virtuosoRef.current?.scrollToIndex({
            index: "LAST",
            align: "end",
            behavior: "auto",
          }),
        );
      }
    }, [messages.length]);

    /* ── Reset scroll flag when data source changes ─────────────── */
    useEffect(() => {
      hasInitialScrollRef.current = false;
    }, [status]);

    /* ── Show "new messages" badge when not at bottom ───────────── */
    useEffect(() => {
      const cur = messages.length;
      const prev = prevMessageCountRef.current;
      if (cur > prev && !isAtBottom && prev > 0) {
        setShowNewMessage(true);
      }
      prevMessageCountRef.current = cur;
    }, [messages.length, isAtBottom]);

    /* ── Item renderer ──────────────────────────────────────────── */
    const itemContent = useCallback(
      (index: number, msg: ChatMessage) => {
        const isLast = index === messages.length - 1;
        if (renderItem) {
          return renderItem(msg, index, isLast, isStreaming);
        }
        return <DefaultMessageItem msg={msg} />;
      },
      [messages.length, isStreaming, renderItem],
    );

    /* ── Loading state ──────────────────────────────────────────── */
    if (status === "loading") {
      return (
        <div className={`flex-1 overflow-hidden ${className ?? ""}`}>
          <ChatSkeleton count={skeletonCount} />
        </div>
      );
    }

    /* ── Main list ──────────────────────────────────────────────── */
    return (
      <div className={`relative flex-1 min-h-0 ${className ?? ""}`}>
        <Virtuoso
          ref={virtuosoRef}
          data={messages}
          followOutput="auto"
          atBottomStateChange={handleAtBottomStateChange}
          atBottomThreshold={100}
          defaultItemHeight={120}
          overscan={500}
          increaseViewportBy={{ top: 300, bottom: 300 }}
          skipAnimationFrameInResizeObserver
          itemContent={itemContent}
          className="h-full"
          components={{ Footer: VirtuosoFooter }}
        />

        <ChatScrollButton
          isAtBottom={isAtBottom}
          showNewMessage={showNewMessage}
          onClick={() => scrollToBottom()}
        />
      </div>
    );
}

"use client";

/* ------------------------------------------------------------------ */
/*  Typing indicator (three animated dots)                             */
/* ------------------------------------------------------------------ */

const dotBase =
  "inline-block h-1.5 w-1.5 rounded-full bg-current opacity-40 animate-[typing-dot_1.4s_ease-in-out_infinite]";

export function ChatTyping({ className }: { className?: string }) {
  return (
    <span
      role="status"
      aria-label="Typing"
      className={`inline-flex items-center gap-1 ${className ?? ""}`}
    >
      <span className={dotBase} style={{ animationDelay: "0ms" }} />
      <span className={dotBase} style={{ animationDelay: "200ms" }} />
      <span className={dotBase} style={{ animationDelay: "400ms" }} />
    </span>
  );
}
